import {InvalidEmailError} from "../errors/invalid-email.js"

export class Email {
  private constructor(public readonly value: string) {}

  static create(email: string): Email {
    const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (!regex.test(email)) {
      throw new InvalidEmailError();
    }

    return new Email(email);
  }
}